/**
 * Validation helper module.
 * Each validator returns an array of error message strings.
 * An empty array means the value passed all checks.
 */

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

/**
 * Validate a user `id` value (route param or body field).
 * Accepts numbers or numeric strings.
 * @param {*} value
 * @param {string} [field='id']
 * @returns {string[]} array of error messages
 */
function validateId(value, field = 'id') {
  const errors = [];
  if (value === undefined || value === null || value === '') {
    errors.push(`"${field}" is required`);
    return errors;
  }
  if (isNaN(Number(value)) || !isFinite(Number(value))) {
    errors.push(`"${field}" must be a numeric value`);
  }
  return errors;
}

/**
 * Validate a user `name` field.
 * Must be a non-empty string between 1 and 100 characters.
 * @param {*} value
 * @param {string} [field='name']
 * @returns {string[]}
 */
function validateName(value, field = 'name') {
  const errors = [];
  if (value === undefined || value === null) {
    errors.push(`"${field}" is required`);
    return errors;
  }
  if (typeof value !== 'string') {
    errors.push(`"${field}" must be a string`);
    return errors;
  }
  if (value.length < 1) {
    errors.push(`"${field}" must be at least 1 character long`);
  }
  if (value.length > 100) {
    errors.push(`"${field}" must be at most 100 characters long`);
  }
  return errors;
}

/**
 * Validate a user `email` field.
 * Must be a string that matches a basic e-mail pattern, max 254 characters.
 * @param {*} value
 * @param {string} [field='email']
 * @returns {string[]}
 */
function validateEmail(value, field = 'email') {
  const errors = [];
  if (value === undefined || value === null) {
    errors.push(`"${field}" is required`);
    return errors;
  }
  if (typeof value !== 'string') {
    errors.push(`"${field}" must be a string`);
    return errors;
  }
  if (value.length > 254) {
    errors.push(`"${field}" must be at most 254 characters long`);
  }
  if (!EMAIL_REGEX.test(value)) {
    errors.push(`"${field}" must be a valid email address`);
  }
  return errors;
}

/**
 * Validate the full user body (name + email).
 * Used by POST /users and PUT /users/:id.
 * @param {object} body
 * @returns {string[]}
 */
function validateUserBody(body) {
  return [
    ...validateName(body.name),
    ...validateEmail(body.email),
  ];
}

/**
 * Validate a numeric route parameter (e.g. req.params.id).
 * @param {string} value  - always a string when coming from req.params
 * @param {string} [field='id']
 * @returns {string[]}
 */
function validateParamId(value, field = 'id') {
  return validateId(value, field);
}

module.exports = {
  validateId,
  validateName,
  validateEmail,
  validateUserBody,
  validateParamId,
};

