/**
 * Validation helper module.
 * Each validator returns an array of error message strings.
 * An empty array means the value is valid.
 */

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
const NAME_MIN = 1;
const NAME_MAX = 100;
const EMAIL_MAX = 254;

/**
 * Validate a user ID (must be a numeric integer > 0).
 * Accepts either a number or a numeric string (e.g. from URL params).
 *
 * @param {*} id
 * @param {string} [field='id'] - label used in error messages
 * @returns {string[]} array of validation errors
 */
function validateId(id, field = 'id') {
  const errors = [];

  if (id === undefined || id === null || id === '') {
    errors.push(`"${field}" is required`);
    return errors;
  }

  const num = Number(id);
  if (!Number.isFinite(num) || !Number.isInteger(num) || num <= 0) {
    errors.push(`"${field}" must be a positive integer`);
  }

  return errors;
}

/**
 * Validate a name field (must be a non-empty string, 1–100 characters).
 *
 * @param {*} name
 * @param {string} [field='name'] - label used in error messages
 * @returns {string[]} array of validation errors
 */
function validateName(name, field = 'name') {
  const errors = [];

  if (name === undefined || name === null) {
    errors.push(`"${field}" is required`);
    return errors;
  }

  if (typeof name !== 'string') {
    errors.push(`"${field}" must be a string`);
    return errors;
  }

  const trimmed = name.trim();
  if (trimmed.length < NAME_MIN) {
    errors.push(`"${field}" must be at least ${NAME_MIN} character`);
  } else if (trimmed.length > NAME_MAX) {
    errors.push(`"${field}" must be at most ${NAME_MAX} characters`);
  }

  return errors;
}

/**
 * Validate an email field (must be a string matching RFC-5321 length limits
 * and a basic address format, max 254 characters).
 *
 * @param {*} email
 * @param {string} [field='email'] - label used in error messages
 * @returns {string[]} array of validation errors
 */
function validateEmail(email, field = 'email') {
  const errors = [];

  if (email === undefined || email === null) {
    errors.push(`"${field}" is required`);
    return errors;
  }

  if (typeof email !== 'string') {
    errors.push(`"${field}" must be a string`);
    return errors;
  }

  if (email.length > EMAIL_MAX) {
    errors.push(`"${field}" must be at most ${EMAIL_MAX} characters`);
  }

  if (!EMAIL_REGEX.test(email)) {
    errors.push(`"${field}" must be a valid email address`);
  }

  return errors;
}

/**
 * Validate a complete user body object.
 * Accepts an options object to control which fields are required vs optional.
 *
 * @param {object} body - request body
 * @param {object} [options]
 * @param {boolean} [options.requireName=true]   - whether name is required
 * @param {boolean} [options.requireEmail=true]  - whether email is required
 * @returns {string[]} array of validation errors
 */
function validateUserBody(body, { requireName = true, requireEmail = true } = {}) {
  const errors = [];

  if (!body || typeof body !== 'object' || Array.isArray(body)) {
    return ['Request body must be a JSON object'];
  }

  const { name, email } = body;

  if (requireName || name !== undefined) {
    errors.push(...validateName(name));
  }

  if (requireEmail || email !== undefined) {
    errors.push(...validateEmail(email));
  }

  return errors;
}

module.exports = {
  validateId,
  validateName,
  validateEmail,
  validateUserBody,
};

