/**
 * validation.js
 * Reusable input-validation helpers for API route handlers.
 *
 * Each validator returns an array of error strings (empty = valid).
 * Use `collectErrors` to run multiple validators and return a unified
 * 400 response when any errors are present.
 */

'use strict';

// ---------------------------------------------------------------------------
// Low-level rule checkers
// ---------------------------------------------------------------------------

/**
 * Validate that a value is present (not undefined, null, or empty string).
 * @param {*}      value - The value to check.
 * @param {string} field - Field name used in the error message.
 * @returns {string|null} Error string or null.
 */
function requireField(value, field) {
  if (value === undefined || value === null || value === '') {
    return `"${field}" is required`;
  }
  return null;
}

/**
 * Validate that a value is a finite integer (or a string representation of one).
 * Accepts numbers and numeric strings; rejects floats, NaN, Infinity.
 * @param {*}      value
 * @param {string} field
 * @returns {string|null}
 */
function requireNumericId(value, field) {
  if (value === undefined || value === null) return null; // presence checked elsewhere
  const num = Number(value);
  if (!Number.isInteger(num) || num <= 0) {
    return `"${field}" must be a positive integer`;
  }
  return null;
}

/**
 * Validate that a value is a non-empty string (not a number, array, etc.).
 * @param {*}      value
 * @param {string} field
 * @returns {string|null}
 */
function requireString(value, field) {
  if (value === undefined || value === null) return null; // presence checked elsewhere
  if (typeof value !== 'string') {
    return `"${field}" must be a string`;
  }
  return null;
}

/**
 * Validate minimum string length.
 * @param {*}      value
 * @param {string} field
 * @param {number} min
 * @returns {string|null}
 */
function minLength(value, field, min) {
  if (typeof value !== 'string') return null; // type checked elsewhere
  if (value.trim().length < min) {
    return `"${field}" must be at least ${min} character${min !== 1 ? 's' : ''} long`;
  }
  return null;
}

/**
 * Validate maximum string length.
 * @param {*}      value
 * @param {string} field
 * @param {number} max
 * @returns {string|null}
 */
function maxLength(value, field, max) {
  if (typeof value !== 'string') return null; // type checked elsewhere
  if (value.length > max) {
    return `"${field}" must not exceed ${max} characters`;
  }
  return null;
}

/**
 * Validate that a value matches a basic RFC-5321-style email format.
 * Checks: local@domain.tld structure, no surrounding whitespace, valid chars.
 * @param {*}      value
 * @param {string} field
 * @returns {string|null}
 */
function requireEmail(value, field) {
  if (typeof value !== 'string') return null; // type checked elsewhere
  // Deliberately readable regex: local part @ domain with at least one dot
  const EMAIL_RE = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  if (!EMAIL_RE.test(value)) {
    return `"${field}" must be a valid email address`;
  }
  return null;
}

// ---------------------------------------------------------------------------
// Composite field validators (combine rules for a single field)
// ---------------------------------------------------------------------------

/**
 * Validate a `name` field: required, string, 1–100 chars.
 * @param {*}  value
 * @param {boolean} required - Whether the field must be present.
 * @returns {string[]} Array of error strings.
 */
function validateName(value, required = true) {
  const errors = [];
  if (required) {
    const e = requireField(value, 'name');
    if (e) { errors.push(e); return errors; } // skip further checks if absent
  }
  if (value === undefined || value === null || value === '') return errors;

  const typeErr = requireString(value, 'name');
  if (typeErr) { errors.push(typeErr); return errors; }

  const minErr = minLength(value, 'name', 1);
  if (minErr) errors.push(minErr);

  const maxErr = maxLength(value, 'name', 100);
  if (maxErr) errors.push(maxErr);

  return errors;
}

/**
 * Validate an `email` field: required, string, valid format, max 254 chars.
 * @param {*}  value
 * @param {boolean} required
 * @returns {string[]}
 */
function validateEmail(value, required = true) {
  const errors = [];
  if (required) {
    const e = requireField(value, 'email');
    if (e) { errors.push(e); return errors; }
  }
  if (value === undefined || value === null || value === '') return errors;

  const typeErr = requireString(value, 'email');
  if (typeErr) { errors.push(typeErr); return errors; }

  const maxErr = maxLength(value, 'email', 254);
  if (maxErr) errors.push(maxErr);

  const fmtErr = requireEmail(value, 'email');
  if (fmtErr) errors.push(fmtErr);

  return errors;
}

/**
 * Validate a route/query `id` parameter: required, positive integer.
 * @param {*}  value
 * @returns {string[]}
 */
function validateId(value) {
  const errors = [];
  const presenceErr = requireField(value, 'id');
  if (presenceErr) { errors.push(presenceErr); return errors; }

  const numErr = requireNumericId(value, 'id');
  if (numErr) errors.push(numErr);

  return errors;
}

// ---------------------------------------------------------------------------
// Response helper
// ---------------------------------------------------------------------------

/**
 * Send a 400 JSON response if any errors exist.
 * Returns `true` when a response was sent (caller should return early),
 * `false` when validation passed.
 *
 * @param {string[]} errors  - Flat array of error strings.
 * @param {object}   res     - Express response object.
 * @returns {boolean}
 */
function sendValidationErrors(errors, res) {
  if (errors.length === 0) return false;
  res.status(400).json({
    error: 'Validation failed',
    details: errors,
  });
  return true;
}

// ---------------------------------------------------------------------------
// Exports
// ---------------------------------------------------------------------------

module.exports = {
  // Low-level rules (useful for custom validation in route handlers)
  requireField,
  requireNumericId,
  requireString,
  minLength,
  maxLength,
  requireEmail,

  // Composite field validators
  validateName,
  validateEmail,
  validateId,

  // Response helper
  sendValidationErrors,
};

