const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

/**
 * Validate a route/query parameter that must be a positive integer ID.
 * @param {string} value  - raw string value (e.g. req.params.id)
 * @param {string} field  - field name used in error messages
 * @returns {string[]} array of validation errors
 */
function validateId(value, field = 'id') {
  const errors = [];
  if (value === undefined || value === null || value === '') {
    errors.push(`"${field}" is required`);
    return errors;
  }
  if (!/^\d+$/.test(String(value)) || Number(value) <= 0) {
    errors.push(`"${field}" must be a positive integer`);
  }
  return errors;
}

/**
 * Validate a name field.
 * @param {*}      value  - value to check
 * @param {string} field  - field name used in error messages
 * @param {object} opts   - { required: bool, minLength: number, maxLength: number }
 * @returns {string[]} array of validation errors
 */
function validateName(value, field = 'name', { required = true, minLength = 1, maxLength = 100 } = {}) {
  const errors = [];
  const missing = value === undefined || value === null || value === '';

  if (missing) {
    if (required) errors.push(`"${field}" is required`);
    return errors;
  }
  if (typeof value !== 'string') {
    errors.push(`"${field}" must be a string`);
    return errors;
  }
  const trimmed = value.trim();
  if (trimmed.length < minLength) {
    errors.push(`"${field}" must be at least ${minLength} character(s) long`);
  }
  if (trimmed.length > maxLength) {
    errors.push(`"${field}" must be at most ${maxLength} characters long`);
  }
  return errors;
}

/**
 * Validate an email field.
 * @param {*}      value  - value to check
 * @param {string} field  - field name used in error messages
 * @param {object} opts   - { required: bool, maxLength: number }
 * @returns {string[]} array of validation errors
 */
function validateEmail(value, field = 'email', { required = true, maxLength = 254 } = {}) {
  const errors = [];
  const missing = value === undefined || value === null || value === '';

  if (missing) {
    if (required) errors.push(`"${field}" is required`);
    return errors;
  }
  if (typeof value !== 'string') {
    errors.push(`"${field}" must be a string`);
    return errors;
  }
  if (value.length > maxLength) {
    errors.push(`"${field}" must be at most ${maxLength} characters long`);
  }
  if (!EMAIL_REGEX.test(value)) {
    errors.push(`"${field}" must be a valid email address`);
  }
  return errors;
}

/**
 * Validate the body of a POST /users (create) request.
 * Both "name" and "email" are required.
 * @param {object} body
 * @returns {string[]} combined array of all validation errors
 */
function validateCreateUser(body) {
  return [
    ...validateName(body.name, 'name', { required: true }),
    ...validateEmail(body.email, 'email', { required: true }),
  ];
}

/**
 * Validate the body of a PUT /users/:id (full update) request.
 * Both "name" and "email" are required for a full replacement.
 * @param {object} body
 * @returns {string[]} combined array of all validation errors
 */
function validateUpdateUser(body) {
  return [
    ...validateName(body.name, 'name', { required: true }),
    ...validateEmail(body.email, 'email', { required: true }),
  ];
}

/**
 * Validate the body of a PATCH /users/:id (partial update) request.
 * At least one field must be provided; present fields are fully validated.
 * @param {object} body
 * @returns {string[]} combined array of all validation errors
 */
function validatePatchUser(body) {
  const errors = [];
  const hasName  = body.name  !== undefined;
  const hasEmail = body.email !== undefined;

  if (!hasName && !hasEmail) {
    errors.push('at least one field ("name" or "email") must be provided');
    return errors;
  }
  if (hasName)  errors.push(...validateName(body.name,   'name',  { required: true }));
  if (hasEmail) errors.push(...validateEmail(body.email, 'email', { required: true }));
  return errors;
}

/**
 * Convenience middleware factory. Runs a validator against req.body or a
 * custom getter and responds with 400 + errors array if validation fails.
 *
 * @param {function} validatorFn  - function(data) => string[]
 * @param {function} [getter]     - optional (req) => data; defaults to req.body
 */
function validate(validatorFn, getter = (req) => req.body) {
  return (req, res, next) => {
    const errors = validatorFn(getter(req));
    if (errors.length > 0) {
      return res.status(400).json({ errors });
    }
    next();
  };
}

module.exports = {
  validateId,
  validateName,
  validateEmail,
  validateCreateUser,
  validateUpdateUser,
  validatePatchUser,
  validate,
};

