// Primitive validators
// ---------------------------------------------------------------------------

/**
 * Validate that a value is present (not undefined, null, or empty string).
 * @param {*}      value     - The value to check.
 * @param {string} fieldName - Used in the error message.
 * @returns {string[]}
 */
function validateRequired(value, fieldName) {
  if (value === undefined || value === null || value === '') {
    return [`"${fieldName}" is required`];
  }
  return [];
}

/**
 * Validate that a value is a finite integer (or a string that represents one).
 * @param {*}      value
 * @param {string} fieldName
 * @returns {string[]}
 */
function validateNumericId(value, fieldName) {
  const errors = [];
  const num = Number(value);
  if (!Number.isFinite(num) || !Number.isInteger(num) || num <= 0) {
    errors.push(`"${fieldName}" must be a positive integer`);
  }
  return errors;
}

/**
 * Validate that a value is a non-empty string.
 * @param {*}      value
 * @param {string} fieldName
 * @returns {string[]}
 */
function validateString(value, fieldName) {
  if (typeof value !== 'string') {
    return [`"${fieldName}" must be a string`];
  }
  return [];
}

/**
 * Validate string length (inclusive bounds).
 * Assumes the value has already been confirmed to be a string.
 * @param {string} value
 * @param {string} fieldName
 * @param {number} min
 * @param {number} max
 * @returns {string[]}
 */
function validateStringLength(value, fieldName, min, max) {
  const errors = [];
  if (typeof value === 'string') {
    if (value.length < min) {
      errors.push(`"${fieldName}" must be at least ${min} character(s)`);
    }
    if (value.length > max) {
      errors.push(`"${fieldName}" must be at most ${max} character(s)`);
    }
  }
  return errors;
}

/**
 * Validate that a value matches a basic email format.
 * RFC-5321 limits the full address to 254 characters; that length cap is
 * enforced separately via validateStringLength.
 * @param {*}      value
 * @param {string} fieldName
 * @returns {string[]}
 */
function validateEmail(value, fieldName) {
  // Require at least: localpart @ domain . tld  (no whitespace)
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  if (typeof value !== 'string' || !emailRegex.test(value)) {
    return [`"${fieldName}" must be a valid email address`];
  }
  return [];
}

// ---------------------------------------------------------------------------
// Composite field validators
// ---------------------------------------------------------------------------

/**
 * Run all validations for a "name" field.
 * Rules: required, string, 1–100 characters.
 * @param {*}      value
 * @param {string} [fieldName='name']
 * @returns {string[]}
 */
function validateNameField(value, fieldName = 'name') {
  const errors = [
    ...validateRequired(value, fieldName),
  ];
  if (errors.length === 0) {
    errors.push(...validateString(value, fieldName));
    errors.push(...validateStringLength(value, fieldName, 1, 100));
  }
  return errors;
}

/**
 * Run all validations for an "email" field.
 * Rules: required, valid email format, max 254 characters.
 * @param {*}      value
 * @param {string} [fieldName='email']
 * @returns {string[]}
 */
function validateEmailField(value, fieldName = 'email') {
  const errors = [
    ...validateRequired(value, fieldName),
  ];
  if (errors.length === 0) {
    errors.push(...validateEmail(value, fieldName));
    errors.push(...validateStringLength(value, fieldName, 1, 254));
  }
  return errors;
}

/**
 * Validate a route-parameter or query-parameter ID.
 * Rules: present, positive integer.
 * @param {*}      value
 * @param {string} [fieldName='id']
 * @returns {string[]}
 */
function validateIdParam(value, fieldName = 'id') {
  const errors = [...validateRequired(value, fieldName)];
  if (errors.length === 0) {
    errors.push(...validateNumericId(value, fieldName));
  }
  return errors;
}

// ---------------------------------------------------------------------------
// Body-level composite validators (return all errors at once)
// ---------------------------------------------------------------------------

/**
 * Validate a request body that must contain both `name` and `email`.
 * @param {object} body
 * @returns {string[]}
 */
function validateUserBody(body) {
  return [
    ...validateNameField(body.name),
    ...validateEmailField(body.email),
  ];
}

/**
 * Validate a partial update body.  At least one of `name` or `email` must be
 * present; whichever fields are provided are fully validated.
 * @param {object} body
 * @returns {string[]}
 */
function validatePartialUserBody(body) {
  const errors = [];
  const hasName  = body.name  !== undefined;
  const hasEmail = body.email !== undefined;

  if (!hasName && !hasEmail) {
    errors.push('At least one of "name" or "email" must be provided');
    return errors;
  }
  if (hasName)  errors.push(...validateNameField(body.name));
  if (hasEmail) errors.push(...validateEmailField(body.email));
  return errors;
}

// ---------------------------------------------------------------------------
// Express middleware factory
// ---------------------------------------------------------------------------

/**
 * Returns an Express middleware that runs `validatorFn` against the request
 * and short-circuits with a 400 response when errors are found.
 *
 * @param {(req: import('express').Request) => string[]} validatorFn
 *   A function that receives the full request object and returns an array of
 *   error strings.
 * @returns {import('express').RequestHandler}
 *
 * @example
 * router.post('/users', validate(req => validateUserBody(req.body)), handler);
 */
function validate(validatorFn) {
  return (req, res, next) => {
    const errors = validatorFn(req);
    if (errors.length > 0) {
      return res.status(400).json({
        error: 'Validation failed',
        details: errors,
      });
    }
    next();
  };
}

// ---------------------------------------------------------------------------
// Exports
// ---------------------------------------------------------------------------

module.exports = {
  // Primitives
  validateRequired,
  validateNumericId,
  validateString,
  validateStringLength,
  validateEmail,
  // Composite field validators
  validateNameField,
  validateEmailField,
  validateIdParam,
  // Body validators
  validateUserBody,
  validatePartialUserBody,
  // Middleware factory
  validate,
};

