/**
 * Validation helper module.
 * Each validator returns an array of error strings (empty = valid).
 * Compose them with validateUser() for route handlers.
 */

'use strict';

// RFC-5321 practical limit for the local + domain parts combined
const EMAIL_MAX_LENGTH = 254;
const NAME_MIN_LENGTH = 1;
const NAME_MAX_LENGTH = 100;

// Matches the vast majority of valid e-mail addresses without being overly
// permissive.  Deliberately avoids look-arounds for broad Node compatibility.
const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

/**
 * Validate that `value` is a finite integer (or a string that parses to one).
 * Returns an array of error strings.
 *
 * @param {*}      value
 * @param {string} fieldName  - used in error messages
 * @returns {string[]}
 */
function validateId(value, fieldName = 'id') {
  const errors = [];

  if (value === undefined || value === null || value === '') {
    errors.push(`'${fieldName}' is required`);
    return errors;
  }

  const num = Number(value);
  if (!Number.isFinite(num) || !Number.isInteger(num)) {
    errors.push(`'${fieldName}' must be a numeric integer (received: ${JSON.stringify(value)})`);
  }

  return errors;
}

/**
 * Validate that `value` is a non-empty string within the allowed length range.
 * Returns an array of error strings.
 *
 * @param {*}      value
 * @param {string} fieldName
 * @param {{ required?: boolean }} [opts]
 * @returns {string[]}
 */
function validateName(value, fieldName = 'name', opts = {}) {
  const errors = [];
  const required = opts.required !== false; // default: required

  if (value === undefined || value === null) {
    if (required) errors.push(`'${fieldName}' is required`);
    return errors;
  }

  if (typeof value !== 'string') {
    errors.push(`'${fieldName}' must be a string (received: ${typeof value})`);
    return errors;
  }

  const trimmed = value.trim();

  if (trimmed.length < NAME_MIN_LENGTH) {
    errors.push(
      `'${fieldName}' must be at least ${NAME_MIN_LENGTH} character(s) long`
    );
  }

  if (trimmed.length > NAME_MAX_LENGTH) {
    errors.push(
      `'${fieldName}' must be at most ${NAME_MAX_LENGTH} characters long (received: ${trimmed.length})`
    );
  }

  return errors;
}

/**
 * Validate that `value` is a properly formatted e-mail address within the
 * allowed length.
 * Returns an array of error strings.
 *
 * @param {*}      value
 * @param {string} fieldName
 * @param {{ required?: boolean }} [opts]
 * @returns {string[]}
 */
function validateEmail(value, fieldName = 'email', opts = {}) {
  const errors = [];
  const required = opts.required !== false; // default: required

  if (value === undefined || value === null) {
    if (required) errors.push(`'${fieldName}' is required`);
    return errors;
  }

  if (typeof value !== 'string') {
    errors.push(`'${fieldName}' must be a string (received: ${typeof value})`);
    return errors;
  }

  const trimmed = value.trim();

  if (trimmed.length === 0) {
    if (required) errors.push(`'${fieldName}' is required`);
    return errors;
  }

  if (trimmed.length > EMAIL_MAX_LENGTH) {
    errors.push(
      `'${fieldName}' must be at most ${EMAIL_MAX_LENGTH} characters long (received: ${trimmed.length})`
    );
  }

  if (!EMAIL_REGEX.test(trimmed)) {
    errors.push(`'${fieldName}' must be a valid email address (received: ${JSON.stringify(trimmed)})`);
  }

  return errors;
}

/**
 * Validate a user payload.  Use `opts.requiredFields` to specify which fields
 * are mandatory (useful for differentiating POST vs PATCH semantics).
 *
 * @param {object} body
 * @param {{ requiredFields?: string[] }} [opts]
 * @returns {string[]}  Array of human-readable error messages.
 */
function validateUser(body, opts = {}) {
  const required = new Set(opts.requiredFields || ['name', 'email']);
  const errors = [];

  if (!body || typeof body !== 'object' || Array.isArray(body)) {
    return ['Request body must be a JSON object'];
  }

  if ('name' in body || required.has('name')) {
    errors.push(...validateName(body.name, 'name', { required: required.has('name') }));
  }

  if ('email' in body || required.has('email')) {
    errors.push(...validateEmail(body.email, 'email', { required: required.has('email') }));
  }

  return errors;
}

/**
 * Express middleware factory.  Runs `validatorFn` and short-circuits with a
 * 400 JSON response listing all errors when validation fails.
 *
 * Usage:
 *   router.post('/users', validate(req => validateUser(req.body)), handler)
 *
 * @param {(req: import('express').Request) => string[]} validatorFn
 * @returns {import('express').RequestHandler}
 */
function validate(validatorFn) {
  return (req, res, next) => {
    const errors = validatorFn(req);
    if (errors.length > 0) {
      return res.status(400).json({ error: 'Validation failed', details: errors });
    }
    next();
  };
}

module.exports = { validateId, validateName, validateEmail, validateUser, validate };

